using namespace std;

class Solution {
public:
    int possibleStringCount(string word, int k) {
        const int MOD = 1e9 + 7;
        vector<int> runs;
        char prev = word[0];
        int count = 1;
        for (size_t i = 1; i < word.size(); ++i) {
            if (word[i] == prev) {
                count++;
            } else {
                runs.push_back(count);
                prev = word[i];
                count = 1;
            }
        }
        runs.push_back(count);

        int sum_runs = 0;
        for (int ni : runs) {
            sum_runs += ni;
        }
        if (sum_runs < k) {
            return 0;
        }

        int total = 1;
        for (int ni : runs) {
            total = (total * ni) % MOD;
        }

        vector<int> dp(k, 0);
        dp[0] = 1;

        for (int ni : runs) {
            vector<int> new_dp(k, 0);
            vector<int> prefix(k, 0);
            prefix[0] = dp[0];
            for (int i = 1; i < k; ++i) {
                prefix[i] = (prefix[i-1] + dp[i]) % MOD;
            }
            for (int s = 1; s < k; ++s) {
                int max_m = min(ni, s);
                int low = s - max_m;
                if (low < 0) low = 0;
                int sum_ways = (prefix[s-1] - (low > 0 ? prefix[low-1] : 0)) % MOD;
                new_dp[s] = sum_ways;
            }
            dp = new_dp;
        }

        int invalid = 0;
        for (int i = 0; i < k; ++i) {
            invalid = (invalid + dp[i]) % MOD;
        }

        int ans = (total - invalid) % MOD;
        if (ans < 0) ans += MOD;
        return ans;
    }
};

